private boolean isVariableStillLiveWithinExpression(
      Node n, Node exprRoot, String variable) {
    while (n != exprRoot) {
      VariableLiveness state = VariableLiveness.MAYBE_LIVE;
      switch (n.getParent().getType()) {
        case Token.OR:
        case Token.AND:
          // If the current node is the first child of
          // AND/OR, be conservative and only consider the READs
          // of the second operand.
          if (n == n.getParent().getFirstChild()) {
            Node secondOperand = n.getNext();
            if (secondOperand != null && !ControlFlowGraph.isEnteringNewCfgNode(secondOperand)) {
              state = isVariableReadBeforeKill(secondOperand, variable);
            }
          } else {
            // If current node is the second operand, check siblings
            for (Node sibling = n.getNext(); sibling != null; sibling = sibling.getNext()) {
              if (!ControlFlowGraph.isEnteringNewCfgNode(sibling)) {
                state = isVariableReadBeforeKill(sibling, variable);
                if (state != VariableLiveness.MAYBE_LIVE) {
                  break;
                }
              }
            }
          }
          break;

        case Token.HOOK:
          // If current node is the condition, check each following
          // branch, otherwise it is a conditional branch and the
          // other branch can be ignored.
          if (n == n.getParent().getFirstChild()) {
            // Current node is the condition, check both branches
            Node trueBranch = n.getNext();
            Node falseBranch = n.getParent().getLastChild();
            if (trueBranch != null && falseBranch != null) {
              state = checkHookBranchReadBeforeKill(trueBranch, falseBranch, variable);
            }
          } else {
            // Current node is one of the branches, check siblings after the HOOK
            for (Node sibling = n.getNext(); sibling != null; sibling = sibling.getNext()) {
              if (!ControlFlowGraph.isEnteringNewCfgNode(sibling)) {
                state = isVariableReadBeforeKill(sibling, variable);
                if (state != VariableLiveness.MAYBE_LIVE) {
                  break;
                }
              }
            }
          }
          break;

        default:
          for (Node sibling = n.getNext(); sibling != null; sibling = sibling.getNext()) {
            if (!ControlFlowGraph.isEnteringNewCfgNode(sibling)) {
              state = isVariableReadBeforeKill(sibling, variable);
              if (state != VariableLiveness.MAYBE_LIVE) {
                break;
              }
            }
          }
      }

      // If we see a READ or KILL there is no need to continue.
      if (state == VariableLiveness.READ) {
        return true;
      } else if (state == VariableLiveness.KILL) {
        return false;
      }
      n = n.getParent();
    }
    return false;
  }

private VariableLiveness isVariableReadBeforeKill(
      Node n, String variable) {

    if (NodeUtil.isName(n) && variable.equals(n.getString())) {
      if (NodeUtil.isLhs(n, n.getParent())) {
        Preconditions.checkState(n.getParent().getType() == Token.ASSIGN);
        // The expression to which the assignment is made is evaluated before
        // the RHS is evaluated (normal left to right evaluation) but the KILL
        // occurs after the RHS is evaluated.
        Node rhs = n.getNext();
        VariableLiveness state = isVariableReadBeforeKill(rhs, variable);
        if (state == VariableLiveness.READ) {
          return state;
        }
        return VariableLiveness.KILL;
      } else {
        return VariableLiveness.READ;
      }
    }

    switch (n.getType()) {
      // Conditionals
      case Token.OR:
      case Token.AND:
        // With a AND/OR the first branch always runs, but the second
        // may not.
        VariableLiveness firstState = isVariableReadBeforeKill(n.getFirstChild(), variable);
        if (firstState != VariableLiveness.MAYBE_LIVE) {
          return firstState;
        }
        // Second operand may not execute, so conservatively return MAYBE_LIVE
        VariableLiveness secondState = isVariableReadBeforeKill(n.getFirstChild().getNext(), variable);
        if (secondState == VariableLiveness.READ) {
          return VariableLiveness.READ;
        }
        return VariableLiveness.MAYBE_LIVE;

      case Token.HOOK:
        VariableLiveness condState = isVariableReadBeforeKill(n.getFirstChild(), variable);
        if (condState != VariableLiveness.MAYBE_LIVE) {
          return condState;
        }
        return checkHookBranchReadBeforeKill(
            n.getFirstChild().getNext(), n.getLastChild(), variable);

      default:
        // Expressions are evaluated left-right, depth first.
        for (Node child = n.getFirstChild();
            child != null; child = child.getNext()) {
          if (!ControlFlowGraph.isEnteringNewCfgNode(child)) { // Not a FUNCTION
            VariableLiveness state = isVariableReadBeforeKill(child, variable);
            if (state != VariableLiveness.MAYBE_LIVE) {
              return state;
            }
          }
        }
    }

    return VariableLiveness.MAYBE_LIVE;
  }

