public void testNestedShortCircuit() {
    // Test nested AND within OR
    inFunction(
        "var a; ((a = 1) && (a = 2)) || (a = 3);",
        "var a; (     1  &&      2 ) ||      3 ;");

    // Test nested OR within AND
    inFunction(
        "var a; ((a = 1) || (a = 2)) && (a = 3);",
        "var a; (     1  ||      2 ) &&      3 ;");
  }

public void testHookWithShortCircuit() {
    // Test HOOK condition with short-circuit
    inFunction(
        "var a; ((a = 1) || (a = 2)) ? (a = 3) : (a = 4);",
        "var a; (     1  ||      2 ) ?      3  :      4 ;");

    // Test HOOK branches with AND
    inFunction(
        "var a; a ? ((a = 1) && (a = 2)) : ((a = 3) && (a = 4));",
        "var a; a ? (     1  &&      2 ) : (     3  &&      4 );");
  }

public void testMultipleShortCircuitWithReturn() {
    // Test multiple short-circuits with return
    inFunction("var a; ((a = 1) && (a = 2)) || (a = 3); return a;");

    // Test HOOK in short-circuit with return
    inFunction("var a; (a = 1) ? ((a = 2) || (a = 3)) : (a = 4); return a;");
  }
